using Microsoft.ML;
using Microsoft.ML.Data;
using Microsoft.ML.Transforms;
using Microsoft.Extensions.ML;

var builder = WebApplication.CreateBuilder(args);

// Train the model and register the pooled prediction engine
var mlContext = new MLContext(seed: 42);
mlContext.ComponentCatalog.RegisterAssembly(typeof(ChurnMappingFactory).Assembly);

var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "customers.csv");

var data = mlContext.Data.LoadFromTextFile<CustomerData>(dataPath, hasHeader: true, separatorChar: ',');

var pipeline = mlContext.Transforms.CustomMapping(new ChurnMappingFactory().GetMapping(), contractName: "ChurnMapping")
    .Append(mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(CustomerData.Region)))
    .Append(mlContext.Transforms.Concatenate("Features",
        nameof(CustomerData.Age), nameof(CustomerData.Income),
        "RegionEncoded", nameof(CustomerData.PurchaseHistory)))
